let exposedPorts = new Map();

function validatePortMappings(config) {
  // Split the configuration file into individual services
  const services = config.split('service:');
  let ports = {};

  services.forEach((service, index) => {
    const serviceConfig = service.trim().split('\n');
    const serviceName = serviceConfig[0].trim();
    const portRange = serviceConfig[2].trim().split('-');

    // Extract port mappings for each service
    const exposedPort = parseInt(portRange[0]);

    // Check if the exposed port is already used by another service
    if (exposedPorts.has(exposedPort)) {
      return false;
    }

    // Add the exposed port to the map with its service name
    exposedPorts.set(exposedPort, serviceName);

    // Store the port mappings in the ports object
    ports[serviceName] = exposedPort;
  });

  // Check for port collisions
  for (const [port, service] of exposedPorts) {
    for (const otherService in ports) {
      if (service !== otherService) {
        const otherPort = ports[otherService];
        if (port === otherPort) {
          return false;
        }
      }
    }
  }

  return true;
}

