from typing import Dict, List

class Solution:
  def validate_port_mappings(self, config: str) -> bool:
    # Create a dictionary to store exposed ports and their corresponding service names
    exposed_ports = {}

    # Split the configuration file into individual services
    services = config.split('service:');
    ports = {}

    for service in services:
      service_config = service.strip().split('\n');
      service_name = service_config[0].strip();
      port_range = service_config[2].strip().split('-');

      # Extract port mappings for each service
      exposed_port = int(port_range[0]);

      # Check if the exposed port is already used by another service
      if exposed_port in exposed_ports:
        return False;

      # Add the exposed port to the dictionary with its service name
      exposed_ports[exposed_port] = service_name;

      # Store the port mappings in the ports dictionary
      ports[service_name] = exposed_port;

    # Check for port collisions
    for port in exposed_ports:
      for other_service in ports:
        if exposed_ports[port] != other_service:
          other_port = ports[other_service]
          if port == other_port:
            return False;
    return True;
